create or replace function public.buy_fee_default_amount(p_acv numeric, p_month date, p_store_id uuid) returns numeric language plpgsql stable security definer set search_path to 'public' as $function$ declare r public.buy_fee_default_rules%rowtype; begin select * into r from public.buy_fee_default_rules b where b.active and b.effective_month <= date_trunc('month', coalesce(p_month, current_date))::date and (b.store_id is null or b.store_id = p_store_id) order by case when b.store_id is not null and b.store_id = p_store_id then 0 else 1 end, b.effective_month desc, b.created_at desc limit 1; if found then if coalesce(p_acv, 0) > r.high_acv_threshold then return r.high_acv_amount; end if; return r.low_acv_amount; end if; if coalesce(p_acv, 0) > 99999 then return 1000; end if; return 500; end; $function$;
create or replace function public.buy_fee_amount(p_vehicle text, p_acv numeric, p_month date, p_store_id uuid) returns numeric language plpgsql stable security definer set search_path to 'public' as $function$ declare v_amount numeric; begin select r.amount into v_amount from public.buy_fee_rules r where r.active and r.effective_month <= date_trunc('month', coalesce(p_month, current_date))::date and (r.store_id is null or r.store_id = p_store_id) and coalesce(p_vehicle, '') ilike r.make_pattern order by case when r.store_id is not null and r.store_id = p_store_id then 0 else 1 end, r.effective_month desc, length(r.make_pattern) desc, r.created_at desc limit 1; if v_amount is not null then return v_amount; end if; return public.buy_fee_default_amount(p_acv, p_month, p_store_id); end; $function$;